import { db, storage } from "./firebase";
import { collection, getDocs, getDoc, addDoc, updateDoc, deleteDoc, doc, query, where } from "firebase/firestore";
import { ref, uploadBytes, getDownloadURL } from "firebase/storage";

const collectionName = "products";
const productCollectionRef = collection(db, collectionName);

class ProductService {
  // Helper function to upload image and get its URL
  async uploadImage(file) {
    try {
      const fileRef = ref(storage, `images/${Date.now()}_${file.name}`); // Use timestamp to ensure unique filenames
      await uploadBytes(fileRef, file);
      return getDownloadURL(fileRef);
    } catch (error) {
      console.error("Error uploading image:", error);
      throw new Error("Failed to upload image");
    }
  }

  // Add a new product
  async addProduct(newProduct, mainImageFile, additionalImageFiles) {
    try {
      // Upload main image if provided
      const mainImageURL = mainImageFile ? await this.uploadImage(mainImageFile) : '';

      // Upload additional images if provided
      const additionalImagesURLs = additionalImageFiles.length > 0
        ? await Promise.all(Array.from(additionalImageFiles).map(file => this.uploadImage(file)))
        : [];

      // Save product data with URLs
      const productData = {
        ...newProduct,
        mainImage: mainImageURL,
        additionalImages: additionalImagesURLs,
      };

      return addDoc(productCollectionRef, productData);
    } catch (error) {
      console.error("Error adding product:", error);
      throw new Error("Failed to add product");
    }
  }

  // Update an existing product
  async updateProduct(id, updatedProduct) {
    try {
      const productDoc = doc(db, collectionName, id);
      await updateDoc(productDoc, updatedProduct);
    } catch (error) {
      console.error("Error updating product:", error);
      throw new Error("Failed to update product");
    }
  }

  // Delete a product
  async deleteProduct(id) {
    try {
      const productDoc = doc(db, collectionName, id);
      await deleteDoc(productDoc);
    } catch (error) {
      console.error("Error deleting product:", error);
      throw new Error("Failed to delete product");
    }
  }

  // Get all products
  async getAllProducts() {
    try {
      return await getDocs(productCollectionRef);
    } catch (error) {
      console.error("Error getting products:", error);
      throw new Error("Failed to get products");
    }
  }

  // Get a single product by ID
  async getProduct(id) {
    try {
      const productDoc = doc(db, collectionName, id);
      return await getDoc(productDoc);
    } catch (error) {
      console.error("Error getting product:", error);
      throw new Error("Failed to get product");
    }
  }

  // Update product quantity
  async updateProductQuantity(productId, newQuantity) {
    try {
      const productRef = doc(db, collectionName, productId);
      await updateDoc(productRef, { quantity: newQuantity });
    } catch (error) {
      console.error("Error updating product quantity:", error);
      throw new Error("Failed to update product quantity");
    }
  }

  // Get products by category and subcategory
  async getProductsByCategoryAndSubcategory(category, subcategory) {
    try {
      const productQuery = query(
        productCollectionRef,
        where("category", "==", category),
        where("subcategory", "==", subcategory)
      );
      return await getDocs(productQuery);
    } catch (error) {
      console.error("Error getting products by category and subcategory:", error);
      throw new Error("Failed to get products by category and subcategory");
    }
  }
}

export default new ProductService();
